// Time:  ctor:        O(1)
//        addText:     O(l)
//        deleteText:  O(k)
//        cursorLeft:  O(k)
//        cursorRight: O(k)
// Space: O(n)

// design, stack
class TextEditor {
public:
    TextEditor() {

    }

    void addText(string text) {
        left_ += text;
    }

    int deleteText(int k) {
        return move(k, &left_, nullptr);
    }

    string cursorLeft(int k) {
        move(k, &left_, &right_);
        return last_characters();
    }

    string cursorRight(int k) {
        move(k, &right_, &left_);
        return last_characters();
    }

private:
    int move(const int k, string *src, string *dst) {
        const int cnt = min(k, static_cast<int>(size(*src)));
        for (int _ = 0; _ < cnt; ++_) {
            if (dst) {
                dst->push_back(src->back());
            }
            src->pop_back();
        }
        return cnt;
    }

    string last_characters() {
        return left_.substr(max(static_cast<int>(size(left_)) - LAST_COUNT, 0), LAST_COUNT);
    }

    static const int LAST_COUNT = 10;
    string left_;
    string right_;
};

# Time:  ctor:        O(1)
#        addText:     O(l)
#        deleteText:  O(k)
#        cursorLeft:  O(k)
#        cursorRight: O(k)
# Space: O(n)

# design, stack
class TextEditor(object):

    def __init__(self):
        self.__LAST_COUNT = 10
        self.__left = []
        self.__right = []

    def addText(self, text):
        """
        :type text: str
        :rtype: None
        """
        for x in text:
            self.__left.append(x)

    def deleteText(self, k):
        """
        :type k: int
        :rtype: int
        """
        return self.__move(k, self.__left, None)

    def cursorLeft(self, k):
        """
        :type k: int
        :rtype: str
        """
        self.__move(k, self.__left, self.__right)
        return self.__last_characters()

    def cursorRight(self, k):
        """
        :type k: int
        :rtype: str
        """
        self.__move(k, self.__right, self.__left)
        return self.__last_characters()

    def __move(self, k, src, dst):
        cnt = min(k, len(src))
        for _ in xrange(cnt):
            if dst is not None:
                dst.append(src[-1])
            src.pop()
        return cnt

    def __last_characters(self):
        return "".join(self.__left[-self.__LAST_COUNT:])
